mapper.select:
SELECT count(*)
FROM sellers s


    s.seller_status = #{status}



    AND s.user_id = #{user_id}



    AND s.seller_id = #{seller_id}



    AND (
        s.company_name LIKE CONCAT("%", #{keyword}, "%")
        or s.representative_name LIKE CONCAT("%", #{keyword}, "%")
    )



    AND s.created_at >= CONCAT(#{startDate}, ' 00:00:00')



    AND s.created_at <= CONCAT(#{endDate}, ' 23:59:59')

mapper.update:
UPDATE sellers
SET seller_status = #{status}
WHERE seller_id = #{seller_id}

mapper.select:
SELECT *, seller_status status
FROM sellers
WHERE user_id = #{user_id}

SELECT s.seller_id,s.user_id,s.company_name,u.photo_name,
/* 작가 전체 상품 리뷰 평균 */ (SELECT COALESCE(ROUND(AVG(r.rating), 1), 0) FROM products p JOIN reviews r ON p.product_id = r.product_id WHERE p.seller_id = s.seller_id AND p.status = 'APPROVED') AS review_avg,
/* 작가 전체 상품 리뷰 수 */ (SELECT COUNT(*) FROM products p JOIN reviews r ON p.product_id = r.product_id WHERE p.seller_id = s.seller_id AND p.status = 'APPROVED') AS review_count,
/* 작가 전체 상품 찜 수 */ (SELECT COUNT(*) FROM products p JOIN favorites f ON p.product_id = f.product_id WHERE p.seller_id = s.seller_id AND p.status = 'APPROVED') AS product_favorite_count
FROM sellers s JOIN users u ON s.user_id = u.user_id WHERE s.seller_id = #{seller_id}

SELECT COUNT(DISTINCT o.order_id) FROM orders o
JOIN order_items oi ON oi.order_id = o.order_id
JOIN products p ON p.product_id = oi.product_id
LEFT JOIN order_item_claims c ON c.order_item_id = oi.order_item_id
WHERE p.seller_id = #{seller_id}





                AND c.status IN (
                    'RETURN_REQUEST',
                    'EXCHANGE_REQUEST',
                    'RETURN_DONE',
                    'EXCHANGE_DONE'
                )



                AND c.status = #{claimTab}





        AND o.status = #{status}

SELECT DISTINCT o.order_id, o.user_id, o.total_amount, o.address_id, o.status, o.created_at, o.updated_at,
c.claim_id AS claim_id, c.status AS claim_status, c.reason AS claim_reason, c.detail_reason AS claim_detail_reason, c.seller_answer AS claim_seller_answer, DATE_FORMAT(c.requested_at, '%Y-%m-%d %H:%i') AS claim_requested_at, DATE_FORMAT(c.completed_at, '%Y-%m-%d %H:%i') AS claim_completed_at,
a.recipient_name AS receiver_name, a.phone AS receiver_phone,
CONCAT( '[', IFNULL(a.zipcode, ''), '] ', IFNULL(a.address, ''), ' ', IFNULL(a.detail_address, '') ) AS delivery_address
FROM orders o JOIN order_items oi ON oi.order_id = o.order_id JOIN products p ON p.product_id = oi.product_id LEFT JOIN order_item_claims c ON c.order_item_id = oi.order_item_id LEFT JOIN addresses a ON a.address_id = o.address_id
WHERE p.seller_id = #{seller_id}
AND c.status IN ( 'RETURN_REQUEST', 'EXCHANGE_REQUEST', 'RETURN_DONE', 'EXCHANGE_DONE' )
AND c.status = #{claimTab}
AND o.status = #{status}
ORDER BY o.order_id DESC LIMIT #{size} OFFSET #{offset}

SELECT *, seller_status status
FROM sellers
WHERE user_id = #{value}
